// Try to make movement smoother by adding interpolated animation between grid positions.
// If the widget is structured code, replace the movement rendering logic with smooth lerp-based rendering.
const replacements = [
  {
    from: /requestAnimationFrame\(\s*gameLoop\s*\)/g,
    to: `requestAnimationFrame(gameLoop)\n// smooth movement support injected`
  }
];

// If we can detect a canvas draw based on snake cells, inject a generic smooth-render layer.
if (/canvas|ctx|drawImage|fillRect|snake/i.test(text)) {
  text = text
    .replace(
      /function\s+drawSnake\s*\([^)]*\)\s*\{[\s\S]*?\n\}/m,
      `function drawSnake() {
  // Smoothly interpolate segment positions between tiles.
  for (let i = 0; i < snake.length; i++) {
    const seg = snake[i];
    const prev = prevSnake[i] || seg;
    const x = prev.x + (seg.x - prev.x) * moveProgress;
    const y = prev.y + (seg.y - prev.y) * moveProgress;
    drawSegment(x, y, i === 0);
  }
}`
    )
    .replace(
      /let\s+snake\s*=\s*\[[\s\S]*?\];/m,
      match => `${match}\nlet prevSnake = snake.map(s => ({ ...s }));\nlet moveProgress = 1;`
    );

  if (!/moveProgress/.test(text)) {
    text += `\n\nlet prevSnake = [];\nlet moveProgress = 1;\nfunction animateSnakeStep(nextSnake) {\n  prevSnake = snake.map(s => ({ ...s }));\n  snake = nextSnake;\n  moveProgress = 0;\n  const start = performance.now();\n  const duration = 120;\n  function tick(now) {\n    moveProgress = Math.min(1, (now - start) / duration);\n    render();\n    if (moveProgress < 1) requestAnimationFrame(tick);\n  }\n  requestAnimationFrame(tick);\n}\n`;
  }
}

await space.current.patchWidget(widget.id, {
  edits: [
